15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	
22	const FIRST_INSURANCE_SURCHARGE = 1.1;
23	const PROCESSING_FEE = 5;
24	
25	// Round up to a whole number in MHPCO's favour, guarding against
26	// floating-point noise (e.g. 197.5000000001) before the ceiling.
27	const roundUpToWhole = (value: number): number => Math.ceil(Math.round(value * 1e6) / 1e6);
28	
29	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
30	  const results = scenario.steps.map((step) => {
31	    const base = step.items.reduce((sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0), 0);
32	    const premium = base * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
33	    return { premium: roundUpToWhole(premium) };
34	  });
35	  return { results };
36	};
